/**
 * pi plugin for harness-memory.
 *
 * Bridges pi lifecycle events to the PiAdapter so that project memories are
 * injected before model calls, policy warnings are surfaced before tools, and
 * tool evidence is captured after tools — all automatically, inside pi.
 *
 * Loaded by pi when registered as a pi package/extension (see package.json
 * `"pi"` manifest, or `pi install npm:harness-memory`). Types for the pi
 * extension surface are defined inline to avoid a hard dependency on
 * `@earendil-works/pi-coding-agent`; pi passes the real ExtensionAPI at runtime.
 *
 * Event mapping:
 *   pi `session_start`       → adapter.initializeSession
 *   pi `before_agent_start`  → adapter.beforeModel  (appends memory advisory to the system prompt)
 *   pi `tool_call`           → adapter.beforeTool   (policy warnings → ui.notify; never blocks)
 *   pi `tool_result`         → adapter.afterTool    (evidence capture + DB persist)
 *   pi `session_shutdown`    → persist DB
 *
 * Advanced features from the prior harness plugin (conversation buffer, session summary,
 * background dream extraction, embedding warmup, audit/file logging, review
 * digest, global memory tier) are intentionally deferred here — this is the
 * core, functional pi integration. Add them as pi event handlers on demand.
 */

import { existsSync, mkdirSync } from "node:fs";
import { dirname, resolve } from "node:path";

import { ActivationEngine } from "../activation";
import { PiAdapter } from "../adapters/pi-adapter";
import type { AdapterAfterToolOutput, AdapterModelRef } from "../adapters/types";
import { openSqlJsDatabase, saveSqlJsDatabase, runMigrations } from "../db";
import { DreamRepository } from "../dream";
import { MemoryRepository } from "../memory";
import { PolicyEngine, PolicyRuleRepository } from "../policy";
import type { Database as SqlJsDatabase } from "sql.js";

// ---------------------------------------------------------------------------
// Minimal inline pi extension surface (no hard runtime dependency)
// ---------------------------------------------------------------------------

interface PiModelRef {
  provider: string;
  id: string;
}

interface PiExtensionContext {
  cwd: string;
  mode?: string;
  hasUI?: boolean;
  model?: PiModelRef | null;
  sessionManager?: { getSessionFile(): string | null };
  ui?: { notify(message: string, kind?: "info" | "warning" | "error"): void };
}

interface PiBeforeAgentStartEvent {
  prompt?: string;
  systemPrompt?: string;
}

interface PiToolCallEvent {
  toolName: string;
  toolCallId: string;
  input: unknown;
}

interface PiToolResultEvent {
  toolName: string;
  toolCallId: string;
  input?: unknown;
  content?: unknown[];
  details?: unknown;
  isError?: boolean;
}

interface PiSessionStartEvent {
  reason?: string;
}

interface PiApi {
  on(event: "session_start", handler: (e: PiSessionStartEvent, ctx: PiExtensionContext) => Promise<void> | void): void;
  on(
    event: "before_agent_start",
    handler: (e: PiBeforeAgentStartEvent, ctx: PiExtensionContext) => Promise<{ systemPrompt?: string } | void>,
  ): void;
  on(event: "tool_call", handler: (e: PiToolCallEvent, ctx: PiExtensionContext) => Promise<void>): void;
  on(event: "tool_result", handler: (e: PiToolResultEvent, ctx: PiExtensionContext) => Promise<void>): void;
  on(event: "session_shutdown", handler: (e: Record<string, unknown>, ctx: PiExtensionContext) => Promise<void> | void): void;
}

// ---------------------------------------------------------------------------
// Defaults
// ---------------------------------------------------------------------------

const DEFAULT_DB_RELATIVE_PATH = ".harness-memory/memory.sqlite";
const PLUGIN_LOG_PREFIX = "[harness-memory]";

function log(...args: unknown[]): void {
  console.log(PLUGIN_LOG_PREFIX, ...args);
}

function warn(...args: unknown[]): void {
  console.warn(PLUGIN_LOG_PREFIX, ...args);
}

/** Best-effort scope ref from a tool's args (looks for a path-like field). */
function extractScopeFromArgs(args: unknown): string | undefined {
  if (args === null || typeof args !== "object") return undefined;
  const obj = args as Record<string, unknown>;
  for (const key of ["path", "filePath", "file", "cwd", "directory"]) {
    const v = obj[key];
    if (typeof v === "string" && v.length > 0) return v.replace(/\\/g, "/");
  }
  return undefined;
}

/** Flatten pi tool-result content blocks into a single text blob. */
function flattenContent(content: unknown[] | undefined): string {
  if (!Array.isArray(content)) return "";
  const parts: string[] = [];
  for (const block of content) {
    if (block !== null && typeof block === "object" && "type" in block) {
      const b = block as Record<string, unknown>;
      if (b.type === "text" && typeof b.text === "string") parts.push(b.text);
    } else if (typeof block === "string") {
      parts.push(block);
    }
  }
  return parts.join("\n");
}

function modelRefFromCtx(ctx: PiExtensionContext): AdapterModelRef | undefined {
  const m = ctx.model;
  if (m === null || m === undefined) return undefined;
  return { providerID: m.provider, modelID: m.id };
}

// ---------------------------------------------------------------------------
// Plugin
// ---------------------------------------------------------------------------

export interface HarnessMemoryPiPluginOptions {
  /** Override the DB path (defaults to <cwd>/.harness-memory/memory.sqlite). */
  dbPath?: string;
}

export function createHarnessMemoryPiPlugin(
  options: HarnessMemoryPiPluginOptions = {},
): (pi: PiApi) => void {
  return function harnessMemoryPiPlugin(pi: PiApi): void {
    let adapter: PiAdapter | null = null;
    let db: SqlJsDatabase | null = null;
    let dbPath = "";
    let currentSessionId: string | undefined;
    const pendingToolArgs = new Map<string, unknown>();

    async function ensureAdapter(ctx: PiExtensionContext): Promise<PiAdapter> {
      if (adapter !== null) return adapter;

      dbPath = options.dbPath ?? resolve(ctx.cwd, DEFAULT_DB_RELATIVE_PATH);
      if (!existsSync(dirname(dbPath))) mkdirSync(dirname(dbPath), { recursive: true });
      await runMigrations(dbPath, { log: () => {}, error: () => {} });

      db = await openSqlJsDatabase(dbPath);
      const memoryRepository = new MemoryRepository(db);
      const activationEngine = new ActivationEngine(memoryRepository);
      const policyRuleRepository = new PolicyRuleRepository(db);
      const policyEngine = new PolicyEngine(policyRuleRepository);
      const dreamRepository = new DreamRepository(db);

      adapter = new PiAdapter({ activationEngine, policyEngine, dreamRepository });
      log("Adapter initialized from", dbPath);
      return adapter;
    }

    function saveDb(): void {
      if (db !== null && dbPath.length > 0) {
        try {
          saveSqlJsDatabase(db, dbPath);
        } catch (error) {
          warn("Failed to persist DB:", error);
        }
      }
    }

    function sessionIdFor(ctx: PiExtensionContext): string {
      const file = ctx.sessionManager?.getSessionFile();
      return file ?? currentSessionId ?? "pi-session";
    }

    // ---- session_start: initialize the adapter session --------------------
    pi.on("session_start", async (_event, ctx) => {
      try {
        const adp = await ensureAdapter(ctx);
        currentSessionId = sessionIdFor(ctx);
        const model = modelRefFromCtx(ctx);
        adp.initializeSession({
          sessionID: currentSessionId,
          agent: "pi",
          model: model === undefined ? undefined : model,
        });
      } catch (error) {
        warn("session_start hook error:", error);
      }
    });

    // ---- before_agent_start: inject activated memories into the prompt ----
    pi.on("before_agent_start", async (event, ctx) => {
      try {
        const adp = await ensureAdapter(ctx);
        const sessionID = sessionIdFor(ctx);
        const model = modelRefFromCtx(ctx);
        const result = await adp.beforeModel({
          sessionID,
          model: model === undefined ? { providerID: "unknown", modelID: "unknown" } : model,
          messageText: event.prompt ?? "",
        });
        const advisory = result.advisoryText;
        if (advisory !== null && advisory.length > 0) {
          const base = event.systemPrompt ?? "";
          return { systemPrompt: base.length > 0 ? `${base}\n\n${advisory}` : advisory };
        }
      } catch (error) {
        warn("before_agent_start hook error:", error);
      }
      return undefined;
    });

    // ---- tool_call: policy warnings (non-blocking) + stash args -----------
    pi.on("tool_call", async (event, ctx) => {
      try {
        pendingToolArgs.set(event.toolCallId, event.input);
        const adp = await ensureAdapter(ctx);
        const sessionID = sessionIdFor(ctx);
        const result = await adp.beforeTool({
          sessionID,
          tool: event.toolName,
          callID: event.toolCallId,
          scopeRef: extractScopeFromArgs(event.input),
        });
        if (result.warningText !== null && ctx.hasUI !== false && ctx.ui) {
          ctx.ui.notify(result.warningText, "warning");
        }
      } catch (error) {
        warn("tool_call hook error:", error);
      }
    });

    // ---- tool_result: capture evidence + persist --------------------------
    pi.on("tool_result", async (event, ctx) => {
      try {
        const adp = await ensureAdapter(ctx);
        const sessionID = sessionIdFor(ctx);
        const args = pendingToolArgs.get(event.toolCallId) ?? event.input ?? {};
        pendingToolArgs.delete(event.toolCallId);
        const output: AdapterAfterToolOutput = {
          title: event.toolName,
          output: flattenContent(event.content),
          metadata: event.details,
        };
        await adp.afterTool(
          {
            sessionID,
            tool: event.toolName,
            callID: event.toolCallId,
            args,
            scopeRef: extractScopeFromArgs(args),
          },
          output,
        );
        saveDb();
      } catch (error) {
        warn("tool_result hook error:", error);
      }
    });

    // ---- session_shutdown: persist ---------------------------------------
    pi.on("session_shutdown", async () => {
      try {
        saveDb();
      } catch (error) {
        warn("session_shutdown hook error:", error);
      }
    });
  };
}

const harnessMemoryPiPlugin = createHarnessMemoryPiPlugin();
export default harnessMemoryPiPlugin;
export { harnessMemoryPiPlugin as HarnessMemoryPlugin };

