// Orchestrator: a meta-extension that curates pi's example extensions into
// conflict-free "profiles" and activates the right bundle for the task.
//
//   - /orchestrate            interactive menu (profiles + individual extensions)
//   - /orchestrate-reload      triggers ctx.reload() (queued as a follow-up by the tool)
//   - orchestrate (tool)       the agent calls this "when appropriate" to enable/disable
//
// Enable = copy examples/<key> -> extensions/<key>, then /reload. The new extensions
// become active on SUBSEQUENT turns (reload happens after the current turn finishes).
// The orchestrator refuses conflicting combos (singleton groups) -> "perfect synergy".

import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { getAgentDir } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { StringEnum } from "@earendil-works/pi-ai";
import { join } from "node:path";
import { existsSync } from "node:fs";
import { createManager, type Result } from "./manage.ts";
import { PROFILES, CATALOG } from "./catalog.ts";

display.text:
// Orchestrator: a meta-extension that curates pi's example extensions into
// conflict-free "profiles" and activates the right bundle for the task.
//
//   - /orchestrate            interactive menu (profiles + individual extensions)
//   - /orchestrate-reload      triggers ctx.reload() (queued as a follow-up by the tool)
//   - orchestrate (tool)       the agent calls this "when appropriate" to enable/disable
//
// Enable = copy examples/<key> -> extensions/<key>, then /reload. The new extensions
// become active on SUBSEQUENT turns (reload happens after the current turn finishes).
// The orchestrator refuses conflicting combos (singleton groups) -> "perfect synergy".

import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { getAgentDir } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { StringEnum } from "@earendil-works/pi-ai";
import { join } from "node:path";
import { existsSync } from "node:fs";
import { createManager, type Result } from "./manage.ts";
import { PROFILES, CATALOG } from "./catalog.ts";

export default function (pi: ExtensionAPI) {
  const agentDir = getAgentDir();
  const extDir = join(agentDir, "extensions");
  const examplesDir = join(extDir, "examples");
  const stateFile = join(extDir, ".orchestrator-state.json");
  const haveExamples = existsSync(examplesDir);
  const mgr = createManager({ extDir, examplesDir, stateFile });

  // --- session_start: gentle, context-aware tip on a fresh startup (not on reload) ---
  pi.on("session_start", async (event, ctx) => {
    if (!haveExamples || event.reason !== "startup") return;
    try {
      const r = await pi.exec("git", ["rev-parse", "--is-inside-work-tree"], { cwd: ctx.cwd, timeout: 3000 });
      if (r.code === 0 && r.stdout.trim() === "true") {
        ctx.ui.notify("In a git repo — /orchestrate git (or ask the agent to enable the git profile).", "info");
      }
    } catch {
      /* ignore */
    }
  });

  // --- /orchestrate-reload: applies changes. Called as a follow-up so the current turn
  //     finishes first; the new extensions are active after reload. ---
  pi.registerCommand("orchestrate-reload", {
    description: "Reload pi to apply orchestrator extension changes",
    handler: async (_args, ctx) => {
      // ctx is ExtensionCommandContext, which exposes reload().
      await ctx.reload();
      return;
    },
  });

  // Helper to (maybe) queue a reload after a change.
  function maybeReload(changed: boolean) {
    if (changed) pi.sendUserMessage("/orchestrate-reload", { deliverAs: "followUp" });
  }

  // --- /orchestrate: interactive menu using built-in dialogs (robust, no custom TUI) ---
  pi.registerCommand("orchestrate", {
    description: "Enable/disable curated bundles of example pi extensions (profiles)",
    handler: async (_args, ctx) => {
      if (!haveExamples) {
        ctx.ui.notify(`Orchestrator: examples dir not found at ${examplesDir}. Sync the official examples first.`, "error");
        return;
      }
      const main = await ctx.ui.select("Orchestrator", [
        "Enable a profile",
        "Disable a profile",
        "Enable an extension",
        "Disable an extension",
        "Status",
        "Reset (disable all managed)",
      ]);
      if (!main) return;

      if (main === "Status") {
        ctx.ui.notify(mgr.status(), "info");
        return;
      }
      if (main === "Reset (disable all managed)") {
        const r = mgr.reset();
        ctx.ui.notify(r.message, r.changed ? "info" : "warning");
        maybeReload(r.changed);
        return;
      }
      if (main === "Enable a profile" || main === "Disable a profile") {
        const names = Object.keys(PROFILES);
        const labels = names.map((n) => `${n} — ${PROFILES[n].desc}`);
        const pick = await ctx.ui.select(main, labels);
        if (!pick) return;
        const prof = names[labels.indexOf(pick)];
        const r = main.startsWith("Enable") ? mgr.enableProfile(prof) : mgr.disableProfile(prof);
        ctx.ui.notify(r.message, r.ok ? "info" : "warning");
        maybeReload(r.changed);
        return;
      }
      if (main === "Enable an extension") {
        const labels = CATALOG.map((e) => `${e.key} — ${e.desc}${e.requiresSetup ? " (needs setup)" : ""}`);
        const pick = await ctx.ui.select("Enable extension", labels);
        if (!pick) return;
        const key = CATALOG[labels.indexOf(pick)].key;
        const r = mgr.enableKey(key);
        ctx.ui.notify(r.message, r.ok ? "info" : "warning");
        maybeReload(r.changed);
        return;
      }
      if (main === "Disable an extension") {
        const managed = mgr.readState().slice().sort();
        if (!managed.length) {
          ctx.ui.notify("Nothing managed by orchestrator to disable.", "warning");
          return;
        }
        const pick = await ctx.ui.select("Disable extension", managed);
        if (!pick) return;
        const r = mgr.disableKey(pick);
        ctx.ui.notify(r.message, r.ok ? "info" : "warning");
        maybeReload(r.changed);
        return;
      }
    },
  });

  // --- orchestrate tool (LLM-facing): the agent activates the right bundle ---
  pi.registerTool({
    name: "orchestrate",
    label: "Orchestrator",
    description:
      "Enable or disable curated bundles ('profiles') of pi example extensions so the right capabilities are active for the task. Changes apply after an automatic /reload, so they take effect on subsequent turns (not the current one). Use action=status to inspect active extensions and action=list to see available profiles. The orchestrator refuses conflicting combinations (singleton UI slots), keeping the setup conflict-free.",
    promptSnippet: "Enable/disable curated bundles of example pi extensions (profiles) matched to the task",
    promptGuidelines: [
      "Use orchestrate at the START of a task to activate the right example-extension bundle; changes take effect after a reload, on later turns — not mid-turn.",
      "Use orchestrate action=enable profile=safe before destructive operations (rm -rf, sudo, git push --force, dropping tables) or when working in sensitive repos.",
      "Use orchestrate action=enable profile=git when working inside a git repository (look for .git).",
      "Use orchestrate action=enable profile=review for code review or navigating a long session.",
      "Use orchestrate action=enable profile=play when a task will take a while and the user is waiting (adds games + finish notifications).",
      "Use orchestrate action=enable profile=focus when the user asks for a minimal/distraction-free interface; profile=ui when they want a richer interface.",
      "Use orchestrate action=enable profile=plan when exploring a codebase before making changes; profile=power for power-user model/tools/session management.",
      "Call orchestrate action=status before enabling to avoid conflicts; if a profile is refused due to a singleton conflict, disable the conflicting profile/extension first.",
      "Profiles layer freely except for singleton UI slots (footer, header, editor, tool rendering, working indicator, titlebar). The orchestrator tells you exactly what conflicts.",
    ],
    parameters: Type.Object({
      action: StringEnum(["enable", "disable", "status", "list", "reset"] as const),
      profile: Type.Optional(Type.String({ description: "Profile name (enable/disable a whole bundle). See action=list." })),
      extension: Type.Optional(
        Type.String({ description: "Single example key, e.g. 'snake.ts' or 'plan-mode' (enable/disable one extension)" }),
      ),
    }),
    async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
      if (!haveExamples) {
        return {
          content: [{ type: "text", text: `Orchestrator: examples dir not found at ${examplesDir}. Sync the official examples first.` }],
          details: { ok: false },
        };
      }
      const action = params.action as "enable" | "disable" | "status" | "list" | "reset";

      if (action === "status") {
        return { content: [{ type: "text", text: mgr.status() }], details: { ok: true } };
      }
      if (action === "list") {
        const lines = ["Profiles (curated, conflict-free bundles):"];
        for (const [n, p] of Object.entries(PROFILES)) {
          lines.push(`- ${n}: ${p.desc}`);
          lines.push(`    when: ${p.when}`);
          lines.push(`    keys: ${p.keys.join(", ")}`);
        }
        lines.push("", `Cataloged extensions: ${CATALOG.length} (use action=enable extension=<key> for a single one).`);
        lines.push(`Examples dir: ${examplesDir}`);
        return { content: [{ type: "text", text: lines.join("\n") }], details: { ok: true } };
      }

      let r: Result;
      if (action === "enable") {
        if (params.profile) r = mgr.enableProfile(params.profile);
        else if (params.extension) r = mgr.enableKey(params.extension);
        else r = { ok: false, message: "enable requires 'profile' or 'extension'", changed: false };
      } else if (action === "disable") {
        if (params.profile) r = mgr.disableProfile(params.profile);
        else if (params.extension) r = mgr.disableKey(params.extension);
        else r = { ok: false, message: "disable requires 'profile' or 'extension'", changed: false };
      } else {
        r = mgr.reset();
      }

      const followup =
        r.changed
          ? "\n\nA /orchestrate-reload has been queued as a follow-up. The new extensions become active on subsequent turns."
          : "";
      if (r.changed) pi.sendUserMessage("/orchestrate-reload", { deliverAs: "followUp" });
      return {
        content: [{ type: "text", text: `${r.message}${followup}` }],
        details: { ok: r.ok, changed: r.changed },
      };
    },
  });
}

