/**
 * baz-guard — repo-deletion safety function.
 * Confirms before destructive bash ops that would delete a whole git repo in
 * the user's home, so repos can't be wiped by mistake. Passive guard (tool_call).
 */

import { existsSync, readdirSync, statSync } from "node:fs";
import { basename, join } from "node:path";
import { homedir } from "node:os";
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

const HOME = homedir();

function escapeRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function isDestructive(cmd: string): boolean {
  if (/\brm\b/.test(cmd) && /-[a-zA-Z]*[rRfF]/.test(cmd)) return true;
  if (/\bgit\s+rm\b/.test(cmd)) return true;
  if (/\bgit\s+reset\s+--hard\b/.test(cmd)) return true;
  if (/\bgit\s+clean\s+(-[a-zA-Z]*f|--force)/.test(cmd)) return true;
  if (/\bgit\s+push\b[^|\n]*(-f\b|--force\b|--force-with-lease\b)/.test(cmd)) return true;
  if (/\bfind\b[^|\n]*-delete\b/.test(cmd)) return true;
  if (/\bshred\b/.test(cmd)) return true;
  if (/\bmv\b[^|\n]*\/dev\/null/.test(cmd)) return true;
  return false;
}

// True if `cmd` would delete/destroy the whole `repoAbs` (root, or root + glob).
function targetsRepoRoot(cmd: string, repoAbs: string, cwd: string): boolean {
  const name = basename(repoAbs);
  const tail = `(\\/(${escapeRegex("*")}|${escapeRegex("**")})?)?(["'\\s]|$)`;
  if (new RegExp(escapeRegex(repoAbs) + tail).test(cmd)) return true;
  if (cwd === HOME && new RegExp("(^|[\\s\"'])" + escapeRegex(name) + tail).test(cmd)) return true;
  if (cwd === repoAbs) {
    if (/(^|[\s"'`])(\.|\*|\.\.)(["'\s]|$)/.test(cmd)) return true;
    if (new RegExp("(^|[\\s\"'])" + escapeRegex(name) + "(\"|'|\\s|$)").test(cmd)) return true;
  }
  return false;
}

function findHomeGitRepos(): string[] {
  const repos: string[] = [];
  try {
    for (const name of readdirSync(HOME)) {
      if (name.startsWith(".")) continue;
      const p = join(HOME, name);
      try {
        if (statSync(p).isDirectory() && existsSync(join(p, ".git"))) repos.push(p);
      } catch {
        /* skip */
      }
    }
  } catch {
    /* skip */
  }
  return repos;
}

export default function bazGuard(pi: ExtensionAPI) {
  let homeRepos = findHomeGitRepos();

  pi.on("session_start", async () => {
    homeRepos = findHomeGitRepos();
  });

  pi.on("before_agent_start", async (event) => {
    const block = `

## BAZ guard

Repo-deletion safety is active. Destructive ops that would delete a whole home git repo (rm -rf <repo>, git rm -r ., git reset --hard, find -delete, etc.) require confirmation. Normal cleanup (rm -rf node_modules, etc.) is unaffected.
`;
    return { systemPrompt: event.systemPrompt + block };
  });

  pi.on("tool_call", async (event, ctx) => {
    if (event.toolName !== "bash") return undefined;
    const cmd = (event.input as { command?: string } | undefined)?.command ?? "";
    if (!cmd || !isDestructive(cmd)) return undefined;

    const repos = homeRepos.length ? homeRepos : findHomeGitRepos();
    const hit = repos.find((repo) => targetsRepoRoot(cmd, repo, ctx.cwd));
    if (!hit) return undefined;

    if (ctx.hasUI) {
      const ok = await ctx.ui.confirm(
        "BAZ guard: destructive op on a repo",
        `This command looks like it would delete or destroy:\n  ${hit}\n\nProceed?`,
      );
      if (!ok) return { block: true, reason: "BAZ guard: user declined destructive repo operation." };
    } else {
      return { block: true, reason: `BAZ guard: refusing destructive op on ${hit} without confirmation.` };
    }
    return undefined;
  });
}

